3898	\begin{lemma}[Two localizations at the same set are canonically isomorphic]
3899	  \label{lem:isLocalizedModule_linearEquiv_mathlib}
3900	  \lean{IsLocalizedModule.linearEquiv}
3901	  \mathlibok
3902	  \textit{Provided by Mathlib.}
3903	  Let \(S \subseteq R\) be a submonoid of a commutative ring and let \(\varphi : M \to M'\) and
3904	  \(\psi : M \to M''\) be \(R\)-linear maps that each exhibit their target as the localization of
3905	  \(M\) at \(S\) (i.e.\ \(\operatorname{IsLocalizedModule} S\, \varphi\) and
3906	  \(\operatorname{IsLocalizedModule} S\, \psi\)). Then there is a canonical \(R\)-linear isomorphism
3907	  \(M' \cong M''\) compatible with \(\varphi, \psi\). In particular the localization lift
3908	  \(\operatorname{IsLocalizedModule.lift} S\, \varphi\, \psi\) is an isomorphism whenever both
3909	  \(\varphi\) and \(\psi\) are localizations of \(M\) at \(S\).
3910	\end{lemma}
