3991	[Section-restriction of \(\widetilde{M}\) localizes (local-model brick)]
3992	  \label{lem:tilde_section_isLocalizedModule}
3993	  \lean{AlgebraicGeometry.tilde_section_isLocalizedModule}
3994	  \uses{lem:tilde_toOpen_isLocalizedModule_mathlib}
3995	  Let \(M\) be an \(R\)-module and \(f \in R\). The section-restriction map
3996	  \(\Gamma(\operatorname{Spec} R, \widetilde{M}) \to \Gamma(D(f), \widetilde{M})\) of the associated
3997	  sheaf \(\widetilde{M}\) exhibits its target as the localization of its source at the powers of
3998	  \(f\): one has \(\operatorname{IsLocalizedModule}(\operatorname{powers} f)\) for it.
3999	\end{lemma}
4000	\begin{proof}
4001	  \uses{lem:tilde_toOpen_isLocalizedModule_mathlib}
4002	  \leanok
4003	  By Lemma~\ref{lem:tilde_toOpen_isLocalizedModule_mathlib} the distinguished-open component
4004	  \(\operatorname{toOpen} : M \to \Gamma(D(f), \widetilde{M})\) is a localization at the powers of
4005	  \(f\), and the global component \(M \to \Gamma(\operatorname{Spec} R, \widetilde{M})\) is an
4006	  isomorphism. Up to this global isomorphism, the section-restriction map is exactly
4007	  \(\operatorname{toOpen}\) over \(D(f)\); transporting the localization property along the
4008	  global-sections isomorphism that identifies \(M\) with \(\Gamma(\operatorname{Spec} R,
4009	  \widetilde{M})\) on the source shows that the section-restriction map is itself a localization at the
4010	  powers of \(f\).
4011	\end{proof}
