4014	[Section-restriction localizes when the counit is an isomorphism (per-piece engine)]
4015	  \label{lem:section_isLocalizedModule_of_isIso_fromTildeGamma}
4016	  \lean{AlgebraicGeometry.section_isLocalizedModule_of_isIso_fromTildeΓ}
4017	  \uses{lem:tilde_section_isLocalizedModule, lem:qcoh_iso_tilde_sections}
